INSERT INTO `tblTraceability` VALUES (1,1,'25','PUR25100023','ECPM0002','BHU1250801','2026-02-09 12:44:17.000000','Morena District, Madhya Pradesh, Earthen Connectâs Basil Honey is a unique and flavorful honey that combines the aromatic essence of basil with the natural sweetness of honey. Harvested from bees that forage on basil flowers, this honey offers a distinct taste that sets it apart from other varieties. The process of collecting this honey involves careful monitoring of the bees to ensure that they predominantly collect nectar from basil plants, thereby preserving the purity and unique flavour profile of the honey.','Ocimum basilicum','Ocimum tenuiflorum (Holy Basil/Tulsi)','Monofloral â Dominant nectar source: Basil blooms','Apis mellifera (European Honeybee)','Morena District, Madhya Pradesh','26.5006Â° N, 78.0010Â° E','~180 meters above sea level','Alluvial & sandy-loam (ideal for basil cultivation)','March 2025 (Spring Bloom Season in Terai)','2026-02-09 00:00:00.000000','Shuddh Madhur Apiary Cooperative, Morena','Zero-pesticide, open-field Basil plantations with mobile bee boxes','17.2% (Lab-tested)','Stainless steel food-grade drums','None â 100% Raw','Golden yellow, herbal-floral Tulsi notes','BHU1250801/trace_BHU1250801_1770621257.pdf','Envirocare Labs Pvt. Ltd., Pune','Cold-extracted via centrifugal method (no heat or pressure)','Coarse filter â Retains natural enzymes and pollen','2026-02-10 00:00:00.000000','Morena, Madhya Pradesh','Hinjewadi Phase 2, Pune, Maharashtra','Delhivery Logistics Pvt. Ltd.','Road Transport â Ambient Temp. (Dry Cargo)','Morena ? Gwalior ? Indore ? Pune','4â5 business days','November 5, 2025','FM-1652059500070327','25kg stainless drums in food-grade corrugated cartons','2026-02-10 00:00:00.000000','Glass Jar â 450g with tamper-proof lid','Hinjewadi Phase 2, Pune, Maharashtra','Glass Jar â 450g with tamper-proof lid','24 Months from packaging date','Cool, dry (&lt;25Â°C), away from direct sunlight','2026-02-11 00:00:00.000000','100% Raw Basil Honey, No Preservatives, No Added Sugar, No Heating','Glass Jar + Metal Lid + Kraft Carton Outer Box','BHU1250801/images/stage_BHU1250801_1770622201.jpg','BHU1250801/images/journey_BHU1250801_1770622201.jpg',1,'GIC','GIC','2026-02-09 15:53:34');
